  { expiresIn = 3600 }: SignedUrlOptions = {}
): Promise<string> {
  const command = new GetObjectCommand({
    Bucket: R2_CONFIG.BUCKET,
    Key: key,
  });

  return getSignedUrl(r2Client, command, { expiresIn });
