"use client";

import { useState, useCallback } from "react";

export type UploadFileStatus = "pending" | "uploading" | "completed" | "error";

export type UploadFileItem = {
  id: string;
  file: File;
  status: UploadFileStatus;
  progress: number;
  error?: string;
};

/**
 * Manages local file-queue state for upload UIs.
 * Handles add, remove, progress updates, and clearing â€”
 * the actual upload transport is decoupled.
 */
export function useUploadQueue() {
  const [files, setFiles] = useState<UploadFileItem[]>([]);
  const [isDragging, setIsDragging] = useState(false);

  const addFiles = useCallback((newFiles: FileList | File[]) => {
    const list = Array.from(newFiles);
    const items: UploadFileItem[] = list.map((file) => ({
      id: crypto.randomUUID(),
      file,
      status: "pending" as const,
      progress: 0,
    }));
    setFiles((prev) => [...prev, ...items]);
  }, []);

  const removeFile = useCallback((id: string) => {
    setFiles((prev) => prev.filter((f) => f.id !== id));
  }, []);

  const updateProgress = useCallback(
    (id: string, progress: number) => {
      setFiles((prev) =>
        prev.map((f) =>
          f.id === id
            ? { ...f, progress, status: progress >= 100 ? "completed" : "uploading" }
            : f
        )
      );
    },
    []
  );

  const markError = useCallback((id: string, error: string) => {
    setFiles((prev) =>
      prev.map((f) => (f.id === id ? { ...f, status: "error", error } : f))
    );
  }, []);

  const clearCompleted = useCallback(() => {
    setFiles((prev) => prev.filter((f) => f.status !== "completed"));
  }, []);

  const clearAll = useCallback(() => setFiles([]), []);

  return {
    files,
    isDragging,
    setIsDragging,
    addFiles,
    removeFile,
    updateProgress,
    markError,
    clearCompleted,
    clearAll,
  };
}
